from __future__ import annotations

from dataclasses import dataclass
from typing import Any

from .ai_service import get_ai_response
from .service import EdgeService


@dataclass
class EdgeDashboard:
    summary: dict[str, Any]
    top_opportunities: list[dict[str, Any]]
    watchlist: list[dict[str, Any]]


@dataclass
class EdgeBriefing:
    """Structured briefing generated by the briefing LLM using Brand DNA."""

    header: str
    top_opportunities: str
    catalyst_summary: str
    watchlist: str
    footer: str
    image_prompt: str
    raw: dict[str, Any]


class EdgeReporter:
    """Builds UI-ready dashboard payloads from EDGE service state."""

    def __init__(self, service: EdgeService) -> None:
        self.service = service

    def build_dashboard(self, top_n: int = 3) -> EdgeDashboard:
        summary = self.service.get_scan_summary()
        top = [rec.to_dict() for rec in self.service.engine.top_opportunities(limit=top_n)]
        watchlist = self.service.list_watchlist()
        return EdgeDashboard(
            summary={
                "total_markets": summary.total_markets,
                "qualified": summary.qualified,
                "watchlist": summary.watchlist,
                "rejected": summary.rejected,
                "top_market_ids": summary.top_market_ids,
                "reject_reason_counts": summary.reject_reason_counts,
                "venue_counts": self.service.engine.repository.venue_counts(),
            },
            top_opportunities=top,
            watchlist=watchlist,
        )

    def build_briefing(self, brand_dna, top_n: int = 3) -> EdgeBriefing:
        """Synthesize a natural-language strategic briefing using the Brand DNA.

        The briefing LLM receives the full BrandDNA system prompt (Strategy +
        Copy + Visual) and the current scan data, then produces a structured
        report shaped by the three DNA blocks.

        Returns an EdgeBriefing with one field per report section, or falls back
        to a minimal plain-text briefing if the AI call fails.
        """
        summary = self.service.get_scan_summary()
        top = [rec.to_dict() for rec in self.service.engine.top_opportunities(limit=top_n)]
        watchlist = self.service.list_watchlist()

        watchlist_lines = (
            "\n".join(
                f"  - {w['market_id']} @ {w['venue']} — {w['state']} "
                f"({', '.join(w['reason_codes'])})"
                for w in watchlist
            )
            if watchlist
            else "  empty"
        )

        scan_context = (
            f"SCAN SUMMARY:\n"
            f"  Total markets evaluated: {summary.total_markets}\n"
            f"  Qualified: {summary.qualified} | Watchlist: {summary.watchlist} | "
            f"Rejected: {summary.rejected}\n\n"
            f"TOP OPPORTUNITIES (ranked by ev_net x confidence):\n"
            + "\n".join(
                f"  [{i + 1}] {rec['market_id']} @ {rec['venue']} — "
                f"action={rec['action']}, ev_net={rec.get('ev_net', 0):.4f}, "
                f"confidence={rec['confidence']:.2f}"
                for i, rec in enumerate(top)
            )
            + f"\n\nWATCHLIST ({len(watchlist)} markets):\n{watchlist_lines}"
        )

        system_prompt = brand_dna.to_briefing_prompt()
        prompt = (
            "Generate a strategic market intelligence briefing based on the following "
            f"scan data.\n\n{scan_context}"
        )

        result = get_ai_response(prompt, task_type="complex", system_prompt=system_prompt)

        if result:
            sections = brand_dna.visual.report_sections
            return EdgeBriefing(
                header=result.get(sections[0], ""),
                top_opportunities=result.get(sections[1], ""),
                catalyst_summary=result.get(sections[2], ""),
                watchlist=result.get(sections[3], ""),
                footer=result.get(sections[4], ""),
                image_prompt=result.get("image_prompt", brand_dna.visual.image_prompt_prefix),
                raw=result,
            )

        # Fallback: plain-text briefing from available scan data
        return EdgeBriefing(
            header=f"Market Intelligence Briefing — {summary.total_markets} markets scanned",
            top_opportunities="\n".join(
                f"{rec['market_id']}: {rec['action']} (ev_net={rec.get('ev_net', 0):.4f})"
                for rec in top
            ),
            catalyst_summary="AI briefing unavailable — see raw scan data.",
            watchlist="\n".join(f"{w['market_id']}: {w['state']}" for w in watchlist),
            footer=(
                f"Qualified: {summary.qualified} | Watchlist: {summary.watchlist} | "
                f"Rejected: {summary.rejected}"
            ),
            image_prompt=brand_dna.visual.image_prompt_prefix,
            raw={},
        )
